// 要監控的戰鬥陀螺分類代碼，之後要加分類直接在這裡加一行即可
const categories = [
  { code: 'XIKBXA', name: '基本組' },
  { code: 'XIKBXB', name: '強化組' },
  { code: 'XIKBXC', name: '戰鬥組' },
  { code: 'KB2X', name: '二代APP專屬組' },
];

return categories.map(c => ({
  json: {
    categoryCode: c.code,
    categoryName: c.name,
    url: `https://shop.funbox.com.tw/category_products/XI/KB/${c.code}.json?limit=50&page=1&sort_by=sell_from-desc`,
  },
}));

// 把每個分類回傳的商品陣列攤平成單一商品清單，並附上庫存狀態判斷
const categoryItems = $('Category List').all();
const responseItems = $input.all();

const allProducts = [];

responseItems.forEach((item, idx) => {
  const categoryCode = categoryItems[idx]?.json?.categoryCode ?? 'unknown';
  const body = item.json;
  const products = Array.isArray(body) ? body : (body?.data ?? []);

  products.forEach(p => {
    const variant = p.variants?.[0] ?? {};
    const qty = variant.inventory_quantity ?? 0;
    const isRedemptionItem = p.price >= 999999; // APP兌換類商品的佔位價格，不是真實售價

    allProducts.push({
      id: p.id,
      title: p.title,
      url: `https://shop.funbox.com.tw${p.url}`,
      photo: p.photo ? (p.photo.startsWith('http') ? p.photo : `https:${p.photo}`) : null,
      sku: variant.sku ?? null,
      price: isRedemptionItem ? null : p.price,
      inventory_quantity: qty,
      stock_status: qty === 0 ? 'sold_out' : 'in_stock',
      category: categoryCode,
    });
  });
});

return allProducts.map(p => ({ json: p }));

// 合併「這次抓到的商品清單」跟「上次記錄的狀態」，算出新上架/補貨
const allItems = $input.all();

// Read Seen File 節點來的那筆會帶 binary.data，商品資料不會
const seenFileItem = allItems.find(i => i.binary && i.binary.data);
const productItems = allItems.filter(i => !(i.binary && i.binary.data));

let seen = {};
if (seenFileItem) {
  const raw = Buffer.from(seenFileItem.binary.data.data, 'base64').toString('utf-8');
  seen = raw.trim() ? JSON.parse(raw) : {};
}

const currentItems = productItems.map(i => i.json);
const isFirstRun = Object.keys(seen).length === 0;
const changes = [];

for (const item of currentItems) {
  const prev = seen[item.id];

  if (!isFirstRun) {
    if (!prev) {
      changes.push({ ...item, changeType: 'new' });
    } else if (prev.stock_status === 'sold_out' && item.stock_status !== 'sold_out') {
      changes.push({ ...item, changeType: 'restocked' });
    }
  }

  seen[item.id] = {
    title: item.title,
    url: item.url,
    price: item.price,
    stock_status: item.stock_status,
    last_seen: new Date().toISOString(),
  };
}

return [{
  json: {
    hasChanges: changes.length > 0,
    changes,
    updatedSeen: seen,
    isFirstRun,
  },
}];

// 把變化清單組成 LINE Flex Message 的 contents
const changes = $json.changes;

const bubbles = changes.slice(0, 12).map(c => {
  const tag = c.changeType === 'new' ? '🆕 新上架' : '🔁 補貨到貨';
  const priceText = c.price ? `NT$ ${c.price}` : '請至商品頁查看價格';

  return {
    type: 'bubble',
    ...(c.photo && {
      hero: {
        type: 'image',
        url: c.photo,
        size: 'full',
        aspectRatio: '1:1',
        aspectMode: 'cover',
      },
    }),
    body: {
      type: 'box',
      layout: 'vertical',
      contents: [
        { type: 'text', text: tag, weight: 'bold', color: '#d60000', size: 'sm' },
        { type: 'text', text: c.title, wrap: true, weight: 'bold', size: 'md', margin: 'md' },
        { type: 'text', text: priceText, size: 'sm', color: '#555555', margin: 'sm' },
      ],
    },
    footer: {
      type: 'box',
      layout: 'vertical',
      contents: [
        { type: 'button', style: 'primary', action: { type: 'uri', label: '查看商品', uri: c.url } },
      ],
    },
  };
});

const altText = changes.length === 1
  ? `${changes[0].changeType === 'new' ? '新上架' : '補貨'}：${changes[0].title}`
  : `陀螺追蹤：${changes.length} 項商品更新`;

return [{
  json: {
    altText,
    contents: changes.length === 1 ? bubbles[0] : { type: 'carousel', contents: bubbles },
  },
}];

// 把更新後的 seen 狀態轉成 binary，準備寫回檔案
const seenJson = JSON.stringify($json.updatedSeen, null, 2);
const buffer = Buffer.from(seenJson, 'utf-8');

return [{
  json: {},
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'application/json',
      fileName: 'funbox_seen.json',
    },
  },
}];
